// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * The batched flat-prefix pipeline must produce exactly the generic evaluator's bag of solutions while actually
 * engaging (ENGAGED counter) and serving repeated probe keys from the run-replay buffer (RUN_REPLAYS counter). The
 * dataset is a chain with hub-blocked subjects: five adjacent subjects share each hub, so the second prefix stage sees
 * runs of identical probe keys — the access shape the pipeline accelerates.
 */
public class LmdbNativeChunkPipelineTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			IRI p4 = vf.createIRI(EX, "p4");
			conn.begin();
			// 50 subjects in blocks of five per hub: adjacent scan rows repeat the hub probe key
			for (int i = 0; i < 50; i++) {
				IRI subject = vf.createIRI(EX, String.format("s%02d", i));
				conn.add(subject, p1, vf.createIRI(EX, "hub" + (i / 5)));
			}
			for (int h = 0; h < 10; h++) {
				IRI hub = vf.createIRI(EX, "hub" + h);
				for (int m = 0; m < 20; m++) {
					IRI mid = vf.createIRI(EX, "mid" + h + "_" + m);
					conn.add(hub, p2, mid);
					for (int t = 0; t < 3; t++) {
						IRI target = vf.createIRI(EX, "t" + h + "_" + m + "_" + t);
						conn.add(mid, p3, target);
						for (int l = 0; l < 3; l++) {
							conn.add(target, p4, vf.createIRI(EX, "leaf" + h + "_" + m + "_" + t + "_" + l));
						}
					}
				}
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void chunkPrefixMatchesGenericAndReplaysRuns() {
		// ?z is unprojected: p3 becomes a COUNT branch; the flat prefix is the two-deep chain p1 -> p2,
		// which the chunk pipeline runs batched with run replay on the repeated hub keys
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z }";
		long engagedBefore = LmdbNativeChunkPipeline.ENGAGED.get();
		long replaysBefore = LmdbNativeChunkPipeline.RUN_REPLAYS.get();

		assertSameAsGeneric(query);

		assertThat(LmdbNativeChunkPipeline.ENGAGED.get())
				.as("the chunk pipeline should have driven the factorized prefix")
				.isGreaterThan(engagedBefore);
		assertThat(LmdbNativeChunkPipeline.RUN_REPLAYS.get())
				.as("adjacent equal probe keys should be served from the replay buffer")
				.isGreaterThan(replaysBefore);
	}

	@Test
	public void chunkPrefixHandlesDistinctAndLimit() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT DISTINCT ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z }");
		// LIMIT without ORDER BY is not row-deterministic across engines: check the count only
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<?> rows = QueryResults.asList(conn.prepareTupleQuery("PREFIX ex: <" + EX + ">\n"
					+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } LIMIT 17").evaluate());
			assertThat(rows).hasSize(17);
		}
	}

	@Test
	public void chunkPrefixMemoServesNonAdjacentKeyRepeats() {
		// index-ordered scans keep depth-1 keys grouped (run replay covers those), but the five
		// subjects of each hub replay the hub's 20 mids per subject, so the depth-2 probe sees
		// every mid key repeatedly at distance 20 — never adjacent, only the per-key memo helps
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?w WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?w . ?w ex:p4 ?z }";
		long memoBefore = LmdbNativeChunkPipeline.MEMO_REPLAYS.get();

		assertSameAsGeneric(query);

		assertThat(LmdbNativeChunkPipeline.MEMO_REPLAYS.get())
				.as("non-adjacent probe-key repeats should be served from the per-key memo")
				.isGreaterThan(memoBefore);
	}

	@Test
	public void chunkPrefixHandlesSingleFlatDepth() {
		// star shape: one-pattern prefix (ScanStage only), both legs factorized away
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?x WHERE { ?x ex:p2 ?y . ?y ex:p3 ?z }");
	}

	@Test
	public void chunkPrefixHandlesPrefixDepthFilters() {
		long engagedBefore = LmdbNativeChunkPipeline.ENGAGED.get();
		// the FILTER reads ?x, covered at the first prefix depth: it runs inside the batched chain
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z . FILTER(?x != ex:hub3) }");
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z . FILTER(isIRI(?y)) }");
		assertThat(LmdbNativeChunkPipeline.ENGAGED.get())
				.as("filtered prefixes should still run on the chunk pipeline")
				.isGreaterThan(engagedBefore);
	}

	@Test
	public void chunkPrefixBuildsHashTableForDistinctKeyFloods() throws Exception {
		// every probe key is distinct, so neither run replay nor the memo ever hits; once the probes
		// have cost as much as one sweep of the small p2 relation, the stage must flip to a
		// hash-join-style build and serve the remaining rows from the table. Parallel pipelines are
		// disabled: they outrank the factorized path and would run the prefix on worker chains instead.
		String previousParallel = System.getProperty("rdf4j.lmdb.parallel.enabled");
		System.setProperty("rdf4j.lmdb.parallel.enabled", "false");
		File hashDir = new File(dataDir, "hash-build");
		SailRepository flood = new SailRepository(new LmdbStore(hashDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try {
			try (SailRepositoryConnection conn = flood.getConnection()) {
				ValueFactory vf = conn.getValueFactory();
				IRI p1 = vf.createIRI(EX, "p1");
				IRI p2 = vf.createIRI(EX, "p2");
				IRI p3 = vf.createIRI(EX, "p3");
				conn.begin();
				// p1 is strictly smallest so it roots the plan; p2's live keys are the flood (one quad
				// per distinct ?x), padded with dead keys so p2 outsizes p1 and stays a probe target
				for (int i = 0; i < 1200; i++) {
					IRI subject = vf.createIRI(EX, String.format("fs%04d", i));
					IRI x = vf.createIRI(EX, String.format("fx%04d", i));
					conn.add(subject, p1, x);
					conn.add(x, p2, vf.createIRI(EX, "fy" + (i % 50)));
				}
				for (int i = 0; i < 800; i++) {
					conn.add(vf.createIRI(EX, String.format("fdead%04d", i)), p2,
							vf.createIRI(EX, "fy" + (i % 50)));
				}
				for (int j = 0; j < 50; j++) {
					IRI y = vf.createIRI(EX, "fy" + j);
					for (int k = 0; k < 40; k++) {
						conn.add(y, p3, vf.createIRI(EX, "ft" + j + "_" + k));
					}
				}
				conn.commit();
			}
			String query = "PREFIX ex: <" + EX + ">\n"
					+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z }";
			long buildsBefore = LmdbNativeChunkPipeline.HASH_BUILDS.get();

			List<String> nativeRows = rows(flood, query);
			String previous = System.getProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
			List<String> genericRows;
			try {
				System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", "false");
				genericRows = rows(flood, query);
			} finally {
				if (previous == null) {
					System.clearProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
				} else {
					System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", previous);
				}
			}
			assertThat(nativeRows).containsExactlyInAnyOrderElementsOf(genericRows);
			assertThat(LmdbNativeChunkPipeline.HASH_BUILDS.get())
					.as("a distinct-key flood over a small pattern range should flip to a hash build")
					.isGreaterThan(buildsBefore);
		} finally {
			flood.shutDown();
			if (previousParallel == null) {
				System.clearProperty("rdf4j.lmdb.parallel.enabled");
			} else {
				System.setProperty("rdf4j.lmdb.parallel.enabled", previousParallel);
			}
		}
	}

	private void assertSameAsGeneric(String query) {
		List<String> nativeRows = rows(repository, query);
		String previous = System.getProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
		List<String> genericRows;
		try {
			System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", "false");
			genericRows = rows(repository, query);
		} finally {
			if (previous == null) {
				System.clearProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
			} else {
				System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", previous);
			}
		}
		assertThat(nativeRows)
				.as("native vs generic for:\n" + query)
				.containsExactlyInAnyOrderElementsOf(genericRows);
	}

	/** Rows canonicalized by sorting binding names: the engines bind in different orders, which is not a diff. */
	private static List<String> rows(SailRepository repo, String query) {
		try (SailRepositoryConnection conn = repo.getConnection()) {
			return QueryResults.asList(conn.prepareTupleQuery(query).evaluate())
					.stream()
					.map(bs -> bs.getBindingNames()
							.stream()
							.sorted()
							.map(name -> name + "=" + bs.getValue(name))
							.collect(Collectors.joining(";")))
					.collect(Collectors.toList());
		}
	}
}
